{
  "confirmAgentImpact": true,
  "fields": {
    "classesDeclared": [
      {"className": "Fast/Transactional", "scopeDefinition": "Accessories, SMB laptop refresh"},
      {"className": "Quarterly/Enterprise", "scopeDefinition": "Mid-size infrastructure deals"},
      {"className": "Programmatic/Annual", "scopeDefinition": "Education and public procurement cycles"},
      {"className": "Strategic/Multiyear", "scopeDefinition": "Global framework deals"}
    ],
    "defaultTempoClassRule": "Quarterly/Enterprise; exceptions = Strategic and Programmatic"
  }
}

{
  "confirmAgentImpact": true,
  "fields": {
    "fastClassAnchor": "First customer meeting",
    "enterpriseAnchor": "Architecture validation",
    "programmaticAnchor": "RFP issuance",
    "strategicAnchor": "Steering committee sign-off",
    "reAnchorPolicy": "Allowed once per deal with manager reason code",
    "clockPauseEvents": ["legal freeze", "procurement blackout", "government election code"],
    "noAnchorStateRule": "Valid for seeded opportunities only"
  }
}

{
  "confirmAgentImpact": true,
  "fields": {
    "band0to30": {"expectedSignals": "Discovery meeting and named champion", "acceptableSilenceDays": 10},
    "band30to90": {"expectedSignals": "Solution validation and pricing discussion", "flatPeriodException": "Flat periods acceptable if procurement calendar is pending"},
    "band90to180": {"expectedSignals": "Commercial/legal movement", "strategicClassException": "No risk flag for missing technical deep-dive in strategic class"},
    "minimumAliveEvidenceRule": "Stakeholder reply or scheduled checkpoint in the last 21 days"
  }
}

{
  "confirmAgentImpact": true,
  "fields": {
    "activationWindows": [{"quarterLabel": "Q1", "description": "Education procurement"}, {"quarterLabel": "Q3", "description": "Enterprise refresh budget release"}],
    "fiscalYearEndLowActivityRule": "Final 3 weeks of fiscal year close",
    "preActivationActivityClassification": "Tagged as seeding/education and not flagged as risk",
    "noActivationEscalationRule": "If activation never occurs within 2 cycles, auto-route to nurture queue"
  }
}

{
  "confirmAgentImpact": true,
  "fields": {
    "accelerationMarkers": ["New economic buyer engaged", "Legal review started", "Budget code confirmed"],
    "decaySignals": ["21+ days of one-sided activity", "Repeated reschedules", "Scope contraction without timeline reset"],
    "decayReviewThresholds": {"fastDays": 30, "enterpriseDays": 45, "strategicDays": 75},
    "extendedToleranceRule": "Strategic and partner-led classes tolerate longer intentional waiting"
  }
}

{
  "confirmAgentImpact": true,
  "fields": {
    "programmaticLifecycleUnit": "Fiscal year",
    "strategicLifecycleUnit": "Multi-year program milestone",
    "formalCheckpoints": ["Annual budget approval", "Board capex cycle", "Partner framework renewal"],
    "strategicAliveEvidence": "Sponsor continuity and roadmap checkpoint",
    "phasedSuccessRule": "Success may be phased as pilot, phase-1 rollout, and scale"
  }
}

{
  "confirmAgentImpact": true,
  "fields": {
    "pauseCondition": "External dependency blocks progress for more than 30 days with a confirmed re-entry date",
    "recycleToNurtureCondition": "Intent exists but budget window is more than 1 quarter out",
    "closeNoDealCondition": "No champion, no budget, and no engagement for the threshold period",
    "authorityRule": {"proposeRole": "Seller", "approveRole": "Manager", "recommendRole": "System"},
    "evidenceNoteCadenceDays": 14
  }
}
